const body = $json.body || $json;
const event = body.event || body.data?.event;

// Só processa messages.upsert
if (event !== 'messages.upsert') {
  return [{ json: { skip: true, reason: 'not_message' } }];
}

const data = body.data || body;
const key = data.key || {};

// Ignora msgs do próprio bot
if (key.fromMe) {
  return [{ json: { skip: true, reason: 'from_me' } }];
}

// Ignora grupos
const remoteJid = key.remoteJid || '';
if (remoteJid.includes('@g.us')) {
  return [{ json: { skip: true, reason: 'group' } }];
}

// Extrair texto
const msg = data.message || {};
let text = msg.conversation || msg.extendedTextMessage?.text || '';
if (!text && msg.audioMessage) text = '[audio]';
if (!text && msg.imageMessage) text = msg.imageMessage.caption || '[imagem]';
if (!text) text = '[mensagem sem texto]';

// Extrair phone
let phone = remoteJid.replace('@s.whatsapp.net', '').replace('@lid', '');

return [{ json: {
  skip: false,
  phone: phone,
  message_text: text,
  message_type: msg.audioMessage ? 'audio' : msg.imageMessage ? 'image' : 'text',
  instance_name: body.instance || '',
  wa_message_id: key.id || '',
  raw: body
} }];

// Verificar se lead está em campanha ativa
const phone = $json.phone;
const apikey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inp1cHNiZ3RvZW9peGZva3pranJvIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTE1NDA4MSwiZXhwIjoyMDkwNzMwMDgxfQ.DyapBTSccnh-0I7am5EP-VsqguKmr0VP95FeGjbXitI';

// Buscar lead pelo telefone
const leadResp = await fetch(
  `https://zupsbgtoeoixfokzkjro.supabase.co/rest/v1/leads?phone_e164=ilike.*${phone}&merged_into_id=is.null&select=id&limit=1`,
  { headers: { 'apikey': apikey, 'Authorization': 'Bearer ' + apikey } }
);
const leads = await leadResp.json();

if (!leads || leads.length === 0) {
  return [{ json: { ...$json, in_campaign: false, reason: 'lead_not_found' } }];
}

const leadId = leads[0].id;

// Buscar se está em campanha ativa
const clResp = await fetch(
  `https://zupsbgtoeoixfokzkjro.supabase.co/rest/v1/campanha_leads?lead_id=eq.${leadId}&status=in.(contatado,em_conversa,aquecido)&select=id,campanha_id&limit=1`,
  { headers: { 'apikey': apikey, 'Authorization': 'Bearer ' + apikey } }
);
const campLeads = await clResp.json();

if (!campLeads || campLeads.length === 0) {
  return [{ json: { ...$json, in_campaign: false, reason: 'not_in_campaign' } }];
}

return [{ json: { ...$json, in_campaign: true, lead_id: leadId, campanha_lead_id: campLeads[0].id, campanha_id: campLeads[0].campanha_id } }];
